Here is function to add job by sending post request for scheduler API .

def add_job(name, interval, sql, ops='update'):
    # send a post request to add job
    endpoint = current_app.config['ENDPOINT']
    path = API_FOR_SCHEDULER['add_job']['path']
    url = '{0}{1}'.format(endpoint, path)
    logger.info('Will add job of rule %s by endpoint: %s' % (name, url))
    logger.info('Add job detail:\nJob name: %s\nInterval: %s\nSQL: %s' % (name, interval, sql))
    if interval == 0:
        job = {
            'func': 'dashboard:job',
            'args': [name, sql, ops],
            'id': name,
        }
        logger.info('One time job: %s will run.' % name)
        logger.info(json.loads(json.dumps(job, default=util.ComplexEncoder)))
        return requests.session().request(
            API_FOR_SCHEDULER['add_job']['method'],
            url,
            data=json.dumps(job, cls=util.ComplexEncoder),
        )
    else:

        job = {
            'func': 'dashboard:job',
            'trigger': 'interval',
            'next_run_time': datetime.datetime.now(),
            'hours': int(str(interval)),
            'args': [name, sql, ops],
            'id': name,
            'replace_existing': True,
            'timezone': utc
        }
        logger.info(json.loads(json.dumps(job, default=util.ComplexEncoder)))
        logger.info('Repeat job: %s will run.' % name)
        return requests.session().request(
            API_FOR_SCHEDULER['add_job']['method'],
            url,
            data=json.dumps(job, cls=util.ComplexEncoder),
        )


And util.py here:
class ComplexEncoder(json.JSONEncoder):
    def default(self, obj):
        if isinstance(obj, datetime):
            return obj.strftime('%Y-%m-%d %H:%M:%S')
